#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#include "controller.h"

#define UART_TRANSPORT_PORT 0
#define UART_TRANSPORT_BAUDRATE 115200
#define UART_TRANSPORT_LINE_BUFFER_SIZE 128

static void print_line(const char *line)
{
    if (line == NULL) return;
    printf("%s", line);
}

static void send_actuators(bool inlet_open, bool heater_on)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    int written = protocol_serialize_act_inlet(inlet_open, buffer, sizeof(buffer));
    if (written >= 0 && (size_t)written < sizeof(buffer)) {
        print_line(buffer);
    }
    written = protocol_serialize_act_heater(heater_on, buffer, sizeof(buffer));
    if (written >= 0 && (size_t)written < sizeof(buffer)) {
        print_line(buffer);
    }
}

static void send_debug(const char *message)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    int written = protocol_serialize_debug(message, buffer, sizeof(buffer));
    if (written >= 0 && (size_t)written < sizeof(buffer)) {
        print_line(buffer);
    }
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) return;
    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static int is_rising_temp(const controller_input_t *prev, const controller_input_t *curr)
{
    if (prev == NULL || curr == NULL) return -1;
    if (prev->last_temperature_ms == 0 && curr->last_temperature_ms == 0) return 0;
    int delta = curr->last_temperature_c - prev->last_temperature_c;
    return (delta > 0 ? 1 : -1);
}

int main(void)
{
    controller_t controller;
    bool inlet_open = false, heater_on = false;
    int level = 0, temp = 0;
    uint32_t prev_temp_ms = 0;
    char lines[UART_TRANSPORT_LINE_BUFFER_SIZE];
    const char *line;

    printf("=== Controller Self-Tests ===\n");
    printf("\n\n");

    /* Test 1: Boot leaves inlet closed and heater off */
    printf("Test 1: Boot state should be SAFE_IDLE\n");
    controller_init(&controller);
    send_actuators(inlet_open, heater_on);
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0) {
        printf("PASS: Boot is SAFE_IDLE\n");
    } else {
        printf("FAIL: Boot state is %s\n", line);
    }

    /* Test 2: Low level (<55) should open inlet and keep heater off */
    printf("\nTest 2: Level 30 (low) should open inlet, heater off\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 30");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE FILLING") == 0 && !heater_on) {
        printf("PASS: Inlet open for low level\n");
    } else {
        printf("FAIL: Level 30 - inlet=%s, heater=%s\n", line ? line : "", heater_on);
    }

    /* Test 3: Safe level with low temp should close inlet and turn on heater */
    printf("\nTest 3: Level 65, Temp 40 (safe + low temp) should close inlet, heater on\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("FAIL: Level 65 should be HEATING but heater is %s\n", line ? line : "");
    } else {
        printf("PASS: Inlet closed for safe level\n");
    }

    /* Test 4: Low temp (<45) in safe level should turn on heater */
    printf("\nTest 4: Level 65, Temp 30 (safe + low temp) should turn on heater\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("FAIL: Level 65 with temp 30 should be HEATING but heater is %s\n", line ? line : "");
    } else {
        printf("PASS: Heater on for low temp in safe level\n");
    }

    /* Test 5: High temp (>48) should close inlet and turn off heater */
    printf("\nTest 5: Level 70, Temp 50 (high temp) should close inlet, heater off\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 70");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0 && heater_on) {
        printf("FAIL: High temp should not be HEATING but heater is %s\n", line ? line : "");
    } else {
        printf("PASS: Heater off for high temp\n");
    }

    /* Test 6: Rising temp in 47-48 range should turn off heater early */
    printf("\nTest 6: Level 65, Temp 47 -> 48 (rising) should turn off heater early\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("PASS: Heater off for rising temp in 47-48 range\n");
    } else {
        printf("FAIL: Rising temp should turn off heater early\n");
    }

    /* Test 7: Falling temp in 47-48 range should turn on heater */
    printf("\nTest 7: Level 65, Temp 48 -> 46 (falling) should turn on heater\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("PASS: Heater on for falling temp in 47-48 range\n");
    } else {
        printf("FAIL: Falling temp should turn on heater\n");
    }

    /* Test 8: Timeout forces safe idle */
    printf("\nTest 8: Sensor timeout should force SAFE_IDLE\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 100");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0) {
        printf("PASS: Timeout forces safe idle\n");
    } else {
        printf("FAIL: Timeout should force safe idle\n");
    }

    /* Test 9: Invalid temperature forces safe idle */
    printf("\nTest 9: Invalid temperature should force SAFE_IDLE\n");
    controller_init(&controller);
    send_line("SENSE INVALIDTEMP 200");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0) {
        printf("PASS: Invalid temperature forces safe idle\n");
    } else {
        printf("FAIL: Invalid temperature should force safe idle\n");
    }

    /* Test 10: Malformed input forces safe idle */
    printf("\nTest 10: Malformed input should force SAFE_IDLE\n");
    controller_init(&controller);
    send_line("BADLINE");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0) {
        printf("PASS: Malformed input forces safe idle\n");
    } else {
        printf("FAIL: Malformed input should force safe idle\n");
    }

    /* Test 11: Hot temperature (>48) should close inlet and turn off heater */
    printf("\nTest 11: Level 70, Temp 52 (hot) should close inlet, heater off\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 70");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0 && !heater_on) {
        printf("PASS: Hot temperature forces safe idle\n");
    } else {
        printf("FAIL: Hot temperature should not be HEATING\n");
    }

    /* Test 12: Level above 75 should close inlet */
    printf("\nTest 12: Level 80 (high) should close inlet, heater off\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 80");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0 && !heater_on) {
        printf("PASS: High level closes inlet\n");
    } else {
        printf("FAIL: High level should close inlet\n");
    }

    /* Test 13: Level below 55 should keep heater off */
    printf("\nTest 13: Level 40 (low) should keep heater off\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 40");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE SAFE_IDLE") == 0 && !heater_on) {
        printf("PASS: Low level keeps heater off\n");
    } else {
        printf("FAIL: Low level should keep heater off\n");
    }

    /* Test 14: Rising temp in 47-48 range causes heater off */
    printf("\nTest 14: Level 65, Temp 47 -> 48 (rising) should turn off heater early\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("PASS: Heater off for rising temp in 47-48 range\n");
    } else {
        printf("FAIL: Rising temp should turn off heater early\n");
    }

    /* Test 15: Holding state */
    printf("\nTest 15: Level 65, Temp 30 (safe + low) should be HOLDING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HOLDING") == 0 && !heater_on) {
        printf("PASS: Holding state for low temp\n");
    } else {
        printf("FAIL: Should be HOLDING state\n");
    }

    /* Test 16: Heating state */
    printf("\nTest 16: Level 65, Temp 40 (safe + low) should be HEATING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("PASS: Heating state for low temp in safe range\n");
    } else {
        printf("FAIL: Should be HEATING state\n");
    }

    /* Test 17: Filling state */
    printf("\nTest 17: Level 30 (low) should be FILLING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 30");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE FILLING") == 0 && !heater_on) {
        printf("PASS: Filling state for low level\n");
    } else {
        printf("FAIL: Should be FILLING state\n");
    }

    /* Test 18: Rising temp in 47-48 causes heater off */
    printf("\nTest 18: Level 65, Temp 47 -> 48 (rising) should turn off heater early\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("PASS: Heater off for rising temp in 47-48 range\n");
    } else {
        printf("FAIL: Rising temp should turn off heater early\n");
    }

    /* Test 19: Falling temp in 47-48 causes heater on */
    printf("\nTest 19: Level 65, Temp 48 -> 46 (falling) should turn on heater\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HEATING") == 0 && !heater_on) {
        printf("PASS: Heater on for falling temp in 47-48 range\n");
    } else {
        printf("FAIL: Falling temp should turn on heater\n");
    }

    /* Test 20: Hold state */
    printf("\nTest 20: Level 65, Temp 30 (safe + low) should be HOLDING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HOLDING") == 0 && !heater_on) {
        printf("PASS: Holding state for low temp\n");
    } else {
        printf("FAIL: Should be HOLDING state\n");
    }

    /* Test 21: Hold state */
    printf("\nTest 21: Level 65, Temp 30 (safe + low) should be HOLDING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HOLDING") == 0 && !heater_on) {
        printf("PASS: Holding state for low temp\n");
    } else {
        printf("FAIL: Should be HOLDING state\n");
    }

    /* Test 22: Hold state */
    printf("\nTest 22: Level 65, Temp 30 (safe + low) should be HOLDING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HOLDING") == 0 && !heater_on) {
        printf("PASS: Holding state for low temp\n");
    } else {
        printf("FAIL: Should be HOLDING state\n");
    }

    /* Test 23: Hold state */
    printf("\nTest 23: Level 65, Temp 30 (safe + low) should be HOLDING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
    line = (const char *)lines;
    if (strcmp(line, "DBG STATE HOLDING") == 0 && !heater_on) {
        printf("PASS: Holding state for low temp\n");
    } else {
        printf("FAIL: Should be HOLDING state\n");
    }

    /* Test 24: Heating state */
    printf("\nTest 24: Level 65, Temp 40 (safe + low) should be HEATING\n");
    controller_init(&controller);
    send_line("SENSE LEVEL 65");
    lines[0] = '\0';
