{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check timeout: stale sensor data > 1000ms means safe all-off */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Check timeout: any sensor not seen validly > 1000ms means safe all-off */
    if (input.kind == CONTROLLER_INPUT_NONE ||
        !controller->has_valid_temperature ||
        !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Check timeout: stale data > 1000ms means safe all-off */
    if (input.kind == CONTROLLER_INPUT_NONE ||
        (controller->last_temperature_ms == 0 && input.now_ms > controller->last_temperature_ms + CONTROLLER_SENSOR_TIMEOUT_MS) ||
        (controller->last_level_ms == 0 && input.now_ms > controller->last_level_ms + CONTROLLER_SENSOR_TIMEOUT_MS)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Check timeout: stale data > 1000ms means safe all-off */
    if (input.kind == CONTROLLER_INPUT_NONE ||
        (controller->last_temperature_ms == 0 && input.now_ms > controller->last_temperature_ms + CONTROLLER_SENSOR_TIMEOUT_MS) ||
        (controller->last_level_ms == 0 && input.now_ms > controller->last_level_ms + CONTROLLER_SENSOR_TIMEOUT_MS)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Parse sensor data */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        // Temperature update only affects state for heating decisions, not actuation

    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        // Level update only affects state for filling decisions, not actuation

    }

    /* Apply control policy */
    bool inlet_open = false;
    bool heater_on = false;
    int temp = controller->last_temperature_c;
    int level = controller->last_level;

    if (level < 60) {
        // Low level: open inlet, keep heater off
        inlet_open = true;
    } else if (level > 75) {
        // High level: close inlet
        inlet_open = false;
    } else if (level >= 60 && level <= 75) {
        // Safe level range
        if (temp < 45) {
            // Low temp in safe level: heater on, close inlet
            heater_on = true;
            inlet_open = false;
        } else {
            // High temp in safe level: close inlet, keep heater off
            inlet_open = false;
            heater_on = false;
        }
    }

    /* Special case for 47-48 range */
    if (temp >= 47 && temp <= 48) {
        // Rising temp causes early heater off
        if (is_rising_temp(&controller_input_t{inlet_open = false, heater_on = false}, &input) == 1) {
            heater_on = false;
        }
        // Falling temp causes heater on
        else if (is_rising_temp(&input, &controller_input_t{inlet_open = false, heater_on = false}) == -1) {
            heater_on = true;
        }
    }

    /* Special case for 48+ range */
    if (temp >= 48) {
        // High temp: close inlet and turn off heater
        inlet_open = false;
        heater_on = false;
    }

    /* Set state */
    controller->state = (inlet_open && heater_on) ? CONTROLLER_STATE_HEATING :
                       (level < 55) ? CONTROLLER_STATE_FILLING :
                       CONTROLLER_STATE_HOLDING;

    output.inlet_open = inlet_open;
    output.heater_on = heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != inlet_open) ||
        (previous_heater_on != heater_on) ||
        (previous_state != controller->state);

    /* Handle timed out state */
    if (output.timed_out) {
        output.state_name = "STATE SAFE_IDLE";
        output.inlet_open = false;
        output.heater_on = false;
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}
